// Master Sheet → TEAM format mapping.
// Sheet баганы нэр монголоор; app дотор Latin field name ашиглана.
//
// Branches handling:
//   primary 'Бүлэг' + optional 'Хавсарсан бүлэг' → branches[] array.
//   ҮАХ захирал + production-related M Event roles also get 'production' branch.
//
// Status filter: 'гарсан' (left) + 'нээлттэй' (open position) excluded from active roster.
//
// Output: { team: [...] }

const rows = $input.all().map(it => it.json);

const BRANCH_MAP = {
  'Нэгдсэн': 'shared',
  'M Event': 'm-event',
  'Camp':    'camp',
};

// Roles that should auto-include 'production' (cross-branch event work)
const PRODUCTION_ROLES = [
  'ҮАХ захирал M EVENT',
  'Event Manager',
  'Агуулах засварын ажилтан',
  'Засвар-Агуулахын ахлах',
  'Агуулах-Логистик 1',
  'Агуулах-Логистик 2',
  'ҮАХ захирал NOMAAD',
  'Кемпийн менежер',
];

function mapBranch(label) {
  if (!label) return null;
  const trimmed = String(label).trim();
  return BRANCH_MAP[trimmed] || null;
}

function normalizeId(raw) {
  if (raw == null) return '';
  const s = String(raw).trim();
  // Pad single/double-digit numeric IDs back to 3 digits to match legacy app IDs ("1"→"001")
  if (/^\d{1,2}$/.test(s)) return s.padStart(3, '0');
  return s;
}

const team = [];
for (const r of rows) {
  if (!r) continue;
  const id = normalizeId(r['ID']);
  if (!id) continue;
  const status = String(r['Төлөв'] || '').trim();
  if (status === 'гарсан' || status === 'нээлттэй') continue; // skip inactive

  const primary = mapBranch(r['Бүлэг']);
  const secondary = mapBranch(r['Хавсарсан бүлэг']);
  const branches = [];
  if (primary) branches.push(primary);
  if (secondary && secondary !== primary) branches.push(secondary);

  const role = String(r['Албан тушаал'] || '').trim();
  if (PRODUCTION_ROLES.includes(role) && !branches.includes('production')) {
    branches.push('production');
  }

  // CEO is special — give access to all branches
  if (id === 'CEO') {
    if (!branches.includes('m-event')) branches.push('m-event');
    if (!branches.includes('camp')) branches.push('camp');
    if (!branches.includes('shared')) branches.push('shared');
    if (!branches.includes('production')) branches.push('production');
  }

  team.push({
    id,
    name: String(r['Овог нэр'] || '').trim(),
    role,
    level: parseInt(r['Зэрэглэл'] || '40', 10) || 40,
    pin: String(r['PIN'] || '').trim(),
    email: String(r['И-мэйл'] || '').trim(),
    branches,
    status: status || 'идэвхтэй',
    seasonal_from: String(r['Улирлын эхлэл'] || '').trim() || null,
    seasonal_to:   String(r['Улирлын төгсгөл'] || '').trim() || null,
  });
}

return [{ json: { team, count: team.length, generated_at: new Date().toISOString() } }];
